create table if not exists neura_friendship_profile (sender_id text primary key,tone_preference text default 'leve',last_checkin_at timestamptz,last_proactive_sent_at timestamptz,opt_out boolean default false,preferred_time_window text default '08:00-22:00',relationship_stage text default 'beta_friend',created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists neura_proactive_messages (id bigserial primary key,sender_id text,message text,reason text,status text,created_at timestamptz default now());
create table if not exists neura_user_preferences (sender_id text primary key,opt_out boolean default false,tone_preference text default 'leve',preferred_time_window text default '08:00-22:00',created_at timestamptz default now(),updated_at timestamptz default now());
